	 WHERE
		(TeamLocationRosterID = @TeamLocationRosterID);

	 /**************
	 * RETURN ROW
	 **************/
	 SELECT * FROM RSU.TeamLocationRosters
	 WHERE
		(TeamLocationRosterID = @TeamLocationRosterID);

END;

